const { app, BrowserWindow, ipcMain } = require('electron');
const { spawn, exec } = require('child_process');
const path = require('path');

let mainWindow;
let flaskProcess;
const FLASK_PORT = 5000;
const FLASK_URL = `http://127.0.0.1:${FLASK_PORT}`;

async function killPortOwner() {
    return new Promise(resolve => {
        exec(
            `powershell.exe -Command "Get-NetTCPConnection -LocalPort ${FLASK_PORT} -ErrorAction SilentlyContinue | ForEach-Object { Stop-Process -Id $_.OwningProcess -Force -ErrorAction SilentlyContinue }"`,
            () => resolve()
        );
    });
}

async function startFlaskBackend() {
    await killPortOwner();
    const backendDir = path.join(__dirname, '..', 'backend');
    flaskProcess = spawn('python', ['app.py'], {
        cwd: backendDir,
        stdio: ['ignore', 'pipe', 'pipe'],
        shell: true
    });
    flaskProcess.stdout.on('data', d => console.log(`Flask: ${d}`));
    flaskProcess.stderr.on('data', d => console.error(`Flask: ${d}`));
    flaskProcess.on('close', code => console.log(`Flask exited: ${code}`));

    for (let i = 0; i < 30; i++) {
        try {
            const r = await fetch(`${FLASK_URL}/api/health`);
            if (r.ok) { console.log('Flask backend ready.'); return true; }
        } catch {}
        await new Promise(r => setTimeout(r, 500));
    }
    console.error('Flask backend failed to start.');
    return false;
}

async function createWindow() {
    const ready = await startFlaskBackend();
    if (!ready) { app.quit(); return; }

    mainWindow = new BrowserWindow({
        width: 1200, height: 800, minWidth: 800, minHeight: 600,
        webPreferences: {
            preload: path.join(__dirname, 'preload.js'),
            nodeIntegration: false,
            contextIsolation: true
        }
    });
    mainWindow.loadFile(path.join(__dirname, 'index.html'));
}

app.whenReady().then(createWindow);
app.on('window-all-closed', () => { if (process.platform !== 'darwin') app.quit(); });
app.on('before-quit', () => { if (flaskProcess) flaskProcess.kill(); });

ipcMain.handle('backend:get', async (_, endpoint) => {
    const r = await fetch(`${FLASK_URL}${endpoint}`);
    return r.json();
});

ipcMain.handle('backend:post', async (_, endpoint, data) => {
    const r = await fetch(`${FLASK_URL}${endpoint}`, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify(data)
    });
    return r.json();
});

