@import url('https://fonts.googleapis.com/css2?family=Inter:wght@400;500;600;700&display=swap');

:root {
    --bg-deep: #060608;
    --bg-panel: #0d0d12;
    --bg-card: #13131a;
    --bg-hover: #1a1a24;
    --gold-bright: #F0C040;
    --gold-dim: #D4A843;
    --gold-muted: #8B7A3D;
    --text-primary: #E8E6E1;
    --text-secondary: #A09A8C;
    --text-muted: #6B6560;
    --border-subtle: #1E1E28;
    --border-gold: rgba(212, 168, 67, 0.3);
    --danger: #E8443A;
    --success: #3AE87A;
    --warning: #E8A83A;
    --font-main: 'Inter', -apple-system, sans-serif;
    --radius: 8px;
    --panel-padding: 20px;
}

* { margin: 0; padding: 0; box-sizing: border-box; }

body {
    font-family: var(--font-main);
    background: var(--bg-deep);
    color: var(--text-primary);
    height: 100vh;
    overflow: hidden;
}

#app {
    display: grid;
    grid-template-rows: auto 1fr;
    height: 100vh;
    gap: 1px;
}

header {
    background: var(--bg-panel);
    padding: 16px var(--panel-padding);
    display: flex;
    align-items: center;
    justify-content: space-between;
    border-bottom: 1px solid var(--border-subtle);
}

header h1 {
    font-size: 1.1em;
    font-weight: 600;
    text-transform: uppercase;
    letter-spacing: 1.5px;
    color: var(--gold-bright);
}

.badge {
    font-size: 0.75em;
    padding: 4px 12px;
    border-radius: 12px;
    background: rgba(58, 232, 122, 0.1);
    color: var(--success);
    border: 1px solid rgba(58, 232, 122, 0.2);
}

#main-content {
    padding: var(--panel-padding);
    overflow-y: auto;
}

.panel {
    background: var(--bg-panel);
    border: 1px solid var(--border-subtle);
    border-radius: var(--radius);
    padding: var(--panel-padding);
    margin-bottom: 16px;
    animation: fadeIn 0.4s ease both;
}

.panel-title {
    font-size: 0.8em;
    font-weight: 600;
    text-transform: uppercase;
    letter-spacing: 1.5px;
    color: var(--gold-dim);
    margin-bottom: 12px;
}

table { width: 100%; border-collapse: collapse; }
th {
    text-align: left;
    font-size: 0.75em;
    text-transform: uppercase;
    letter-spacing: 1px;
    color: var(--text-muted);
    padding: 8px 12px;
    border-bottom: 1px solid var(--border-subtle);
}
td {
    padding: 10px 12px;
    font-size: 0.9em;
    color: var(--text-secondary);
    border-bottom: 1px solid var(--border-subtle);
}
tr:hover td { background: var(--bg-hover); }

.progress-bar {
    height: 6px;
    background: var(--bg-card);
    border-radius: 3px;
    overflow: hidden;
    margin-top: 6px;
}
.progress-fill {
    height: 100%;
    background: linear-gradient(90deg, var(--gold-dim), var(--gold-bright));
    border-radius: 3px;
    transition: width 0.3s ease;
    box-shadow: 0 0 8px rgba(240, 192, 64, 0.3);
}

.stat-value {
    font-size: 1.8em;
    font-weight: 700;
    color: var(--gold-bright);
}
.stat-label {
    font-size: 0.75em;
    color: var(--text-muted);
    text-transform: uppercase;
    letter-spacing: 1px;
}

::-webkit-scrollbar { width: 5px; }
::-webkit-scrollbar-track { background: transparent; }
::-webkit-scrollbar-thumb { background: var(--gold-muted); border-radius: 3px; }

@keyframes fadeIn {
    from { opacity: 0; transform: translateY(6px); }
    to { opacity: 1; transform: translateY(0); }
}

